    def _generate_record_fingerprint(self, request: StrategyRecordRequest) -> str:
        fingerprint_data = {
            "object_code": request.object_code,
            "occur_time": request.occur_time.isoformat(),
            "config_rules": json.dumps(request.config_rules, sort_keys=True),
            "evidence_summary": request.evidence_summary,
        }
        fingerprint_str = json.dumps(fingerprint_data, sort_keys=True)
        return hashlib.sha256(fingerprint_str.encode()).hexdigest()[:32]

    def validate_fields(self, request: StrategyRecordRequest) -> List[ValidationDetail]:
        errors = []
        required_rule_fields = ["action_type", "parameters"]

        for field in required_rule_fields:
            if field not in request.config_rules:
                errors.append(
                    ValidationDetail(
                        field_name=f"config_rules.{field}",
                        issue_type="missing_field",
                        message=f"配置规则缺少必填字段：{field}",
                    )
                )

        if "parameters" in request.config_rules:
            params = request.config_rules["parameters"]
            if not isinstance(params, dict):
                errors.append(
                    ValidationDetail(
                        field_name="config_rules.parameters",
                        issue_type="invalid_type",
                        message="parameters必须为字典类型",
                    )
                )
            else:
                if "water_level" not in params and "flow_rate" not in params:
                    errors.append(
                        ValidationDetail(
                            field_name="config_rules.parameters",
                            issue_type="insufficient_data",
                            message="参数必须包含water_level或flow_rate",
                        )
                    )

        return errors

    def check_duplicate(self, request: StrategyRecordRequest) -> Tuple[bool, Optional[str]]:
        fingerprint = self._generate_record_fingerprint(request)
        if fingerprint in self.processed_records_cache:
            cached = self.processed_records_cache[fingerprint]
            time_diff = request.occur_time - cached["occur_time"]
            if abs(time_diff.total_seconds()) < 3600:
                return True, cached["record_id"]
        return False, None

    def match_rules(self, request: StrategyRecordRequest) -> Tuple[List[RuleMatchDetail], List[Dict[str, Any]]]:
        matched_rules = []
        rule_conflicts = []
        params = request.config_rules.get("parameters", {})
        action_type = request.config_rules.get("action_type", "")

        for rule in self.system_rules:
            is_match = False
            actual_value = None
            expected_value = None

            if rule["rule_type"] == RuleType.START_PERMIT and action_type == "start":
                water_level = params.get("water_level", 0)
                if water_level <= 2.5:
                    is_match = True
                    actual_value = water_level
                    expected_value = "> 2.5"

            elif rule["rule_type"] == RuleType.STOP_PERMIT and action_type == "stop":
                flow_rate = params.get("flow_rate", 0)
                if flow_rate >= 0.5:
                    is_match = True
                    actual_value = flow_rate
                    expected_value = "< 0.5"

            elif rule["rule_type"] == RuleType.RAINFALL_THRESHOLD:
                rainfall = params.get("rainfall_1h", 0)
                if rainfall > 50 and action_type != "start":
                    is_match = True
                    actual_value = rainfall
                    expected_value = "> 50 (需启泵)"

            elif rule["rule_type"] == RuleType.TIME_WINDOW:
                hour = request.occur_time.hour
                if (7 <= hour <= 9) or (17 <= hour <= 19):
                    is_match = True
                    actual_value = f"{hour:02d}:{request.occur_time.minute:02d}"
                    expected_value = "非高峰时段"

            elif rule["rule_type"] == RuleType.EQUIPMENT_STATUS:
                health = params.get("equipment_health", 100)
                if health < 80:
                    is_match = True
                    actual_value = health
                    expected_value = ">= 80"

            elif rule["rule_type"] == RuleType.WATER_LEVEL_THRESHOLD and action_type == "start":
                water_level = params.get("water_level", 1.0)
                if water_level < 0.5:
                    is_match = True
                    actual_value = water_level
                    expected_value = ">= 0.5"

            if is_match:
                matched_rules.append(
                    RuleMatchDetail(
                        rule_id=rule["rule_id"],
                        rule_type=rule["rule_type"],
                        rule_name=rule["rule_name"],
                        matched_condition=rule["condition"],
                        expected_value=expected_value,
                        actual_value=actual_value,
                        severity=rule["severity"],
                    )
                )

        start_rules = [r for r in matched_rules if r.rule_type in [RuleType.START_PERMIT, RuleType.WATER_LEVEL_THRESHOLD]]
        stop_rules = [r for r in matched_rules if r.rule_type == RuleType.STOP_PERMIT]

        if start_rules and stop_rules:
            rule_conflicts.append(
                {
                    "conflict_type": "action_conflict",
                    "conflicting_rules": [r.rule_id for r in start_rules + stop_rules],
                    "description": "同时命中启泵和停泵规则，存在动作冲突",
                }
            )

        critical_rules = [r for r in matched_rules if r.severity == "critical"]
        if len(critical_rules) > 1:
            rule_conflicts.append(
                {
                    "conflict_type": "multiple_critical",
                    "conflicting_rules": [r.rule_id for r in critical_rules],
                    "description": "同时命中多条严重规则，需优先级判断",
                }
            )

        return matched_rules, rule_conflicts

    def check_calibration(self, request: StrategyRecordRequest) -> List[DifferenceHint]:
        hints = []
        params = request.config_rules.get("parameters", {})

        if "water_level" in params:
            if not params.get("water_level_calibrated", False):
                hints.append(
                    DifferenceHint(
                        hint_type=BlockReason.CALIBRATION_ERROR,
                        field="water_level",
                        current_value=params["water_level"],
                        reference_value="需校准后的值",
                        description="水位数据未经过校准，计算口径可能存在偏差",
                    )
                )

        if "flow_rate" in params:
            flow_rate = params["flow_rate"]
            if flow_rate < 0 or flow_rate > 100:
                hints.append(
                    DifferenceHint(
                        hint_type=BlockReason.CALIBRATION_ERROR,
                        field="flow_rate",
                        current_value=flow_rate,
                        reference_value="正常范围 0-100",
                        description="流量值超出正常量程范围，可能存在传感器异常",
                    )
                )

        if "rainfall_1h" in params:
            rainfall = params["rainfall_1h"]
            if rainfall > 200:
                hints.append(
                    DifferenceHint(
                        hint_type=BlockReason.CALIBRATION_ERROR,
                        field="rainfall_1h",
                        current_value=rainfall,
                        reference_value="历史极值 180",
                        description="小时降雨量超过历史极值，建议人工复核数据准确性",
                    )
                )

        return hints

    def judge(
        self,
        request: StrategyRecordRequest,
        validation_errors: List[ValidationDetail],
        matched_rules: List[RuleMatchDetail],
        is_duplicate: bool,
        rule_conflicts: List[Dict[str, Any]],
        calibration_hints: List[DifferenceHint],
    ) -> Tuple[JudgmentResult, Optional[BlockReason], str, List[DifferenceHint], bool]:

        difference_hints = []

        if validation_errors:
            missing_fields = [e for e in validation_errors if e.issue_type == "missing_field"]
            if missing_fields:
                for e in missing_fields:
                    difference_hints.append(
                        DifferenceHint(
                            hint_type=BlockReason.MISSING_FIELDS,
                            field=e.field_name,
                            description=e.message,
                        )
                    )
                return (
                    JudgmentResult.BLOCK,
                    BlockReason.MISSING_FIELDS,
                    f"字段校验不通过，缺少{len(missing_fields)}个必填字段",
                    difference_hints,
                    False,
                )

        if is_duplicate:
            difference_hints.append(
                DifferenceHint(
                    hint_type=BlockReason.DUPLICATE_SUBMISSION,
                    description="相同的策略记录在1小时内已提交过",
                )
            )
            return (
                JudgmentResult.BLOCK,
                BlockReason.DUPLICATE_SUBMISSION,
                "检测到重复提交，相同记录在1小时内已处理",
                difference_hints,
                False,
            )

        if rule_conflicts:
            for conflict in rule_conflicts:
                difference_hints.append(
                    DifferenceHint(
                        hint_type=BlockReason.RULE_CONFLICT,
                        field="config_rules",
                        current_value=conflict["conflicting_rules"],
                        description=conflict["description"],
                    )
                )
            return (
                JudgmentResult.BLOCK,
                BlockReason.RULE_CONFLICT,
                f"检测到{len(rule_conflicts)}处规则冲突，需先解决冲突",
                difference_hints,
                False,
            )

        blocking_rules = [r for r in matched_rules if r.severity in ["critical", "high"]]
        review_required_rules = [r for r in matched_rules if r.severity == "medium"]

        if blocking_rules:
            for r in blocking_rules:
                difference_hints.append(
                    DifferenceHint(
                        hint_type=BlockReason.RULE_HIT,
                        field=r.rule_type,
                        current_value=r.actual_value,
                        reference_value=r.expected_value,
                        description=f"规则[{r.rule_name}]命中：{r.matched_condition}",
                    )
                )
            return (
                JudgmentResult.BLOCK,
                BlockReason.RULE_HIT,
                f"命中{len(blocking_rules)}条阻断规则，操作不通过",
                difference_hints,
                False,
            )

        needs_review = any(
            rule.get("manual_review_required", False)
            for rule in self.system_rules
            if any(r.rule_id == rule["rule_id"] for r in review_required_rules)
        )

        if calibration_hints:
            difference_hints.extend(calibration_hints)
            if any(h.hint_type == BlockReason.CALIBRATION_ERROR for h in calibration_hints):
                needs_review = True

        if needs_review or review_required_rules:
            for r in review_required_rules:
                difference_hints.append(
                    DifferenceHint(
                        hint_type=BlockReason.MANUAL_REVIEW_REQUIRED,
                        field=r.rule_type,
                        current_value=r.actual_value,
                        reference_value=r.expected_value,
                        description=f"规则[{r.rule_name}]触发，需人工复核",
                    )
                )
            return (
                JudgmentResult.PENDING_REVIEW,
                BlockReason.MANUAL_REVIEW_REQUIRED,
                "需要人工复核",
                difference_hints,
                True,
            )

        if matched_rules:
            for r in matched_rules:
                difference_hints.append(
                    DifferenceHint(
                        hint_type=BlockReason.RULE_HIT,
                        field=r.rule_type,
                        current_value=r.actual_value,
                        reference_value=r.expected_value,
                        description=f"规则[{r.rule_name}]命中但不阻断：{r.matched_condition}",
                    )
                )

        return (
            JudgmentResult.PASS,
            None,
            "准入判断通过，所有规则校验完成",
            difference_hints,
            False,
        )

    def cache_processed_record(self, record_id: str, request: StrategyRecordRequest):
        fingerprint = self._generate_record_fingerprint(request)
        self.processed_records_cache[fingerprint] = {
            "record_id": record_id,
            "occur_time": request.occur_time,
            "cached_at": datetime.now(),
        }

    def get_calibration_note(self, matched_rules: List[RuleMatchDetail]) -> Optional[str]:
        if not matched_rules:
            return None
        notes = []
        for matched in matched_rules:
            for rule in self.system_rules:
                if rule["rule_id"] == matched.rule_id:
                    notes.append(f"{rule['rule_name']}: {rule['calibration']}")
        return "; ".join(notes) if notes else None
